/**
 * @summary Submit answers for a quiz attempt and get score
 */
export const getSubmitQuizAttemptUrl = () => {
  return `/api/quiz-attempts`;
};

export const submitQuizAttempt = async (
  submitQuizAttemptBody: SubmitQuizAttemptBody,
  options?: RequestInit,
): Promise<QuizAttemptResult> => {
  return customFetch<QuizAttemptResult>(getSubmitQuizAttemptUrl(), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(submitQuizAttemptBody),
  });
};

export const getSubmitQuizAttemptMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof submitQuizAttempt>>,
    TError,
    { data: BodyType<SubmitQuizAttemptBody> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof submitQuizAttempt>>,
  TError,
  { data: BodyType<SubmitQuizAttemptBody> },
  TContext
> => {
  const mutationKey = ["submitQuizAttempt"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof submitQuizAttempt>>,
    { data: BodyType<SubmitQuizAttemptBody> }
  > = (props) => {
    const { data } = props ?? {};

    return submitQuizAttempt(data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type SubmitQuizAttemptMutationResult = NonNullable<
  Awaited<ReturnType<typeof submitQuizAttempt>>
>;
export type SubmitQuizAttemptMutationBody = BodyType<SubmitQuizAttemptBody>;
export type SubmitQuizAttemptMutationError = ErrorType<unknown>;

